const data = $input.first().json;
const query = data.query || data.params || {};
const project_id = query.project_id || data.project_id || '';
const action = query.action || data.action || 'unknown';

return [{ json: { project_id, action, raw_keys: Object.keys(data).join(',') } }];

const rows = $input.all().map(r => r.json);
if (rows.length === 0) {
  return [{ json: { orders: [], noEmail: [], noSupplier: [], text: '⚠️ Keine offenen Materialien gefunden.', projectId: '', summaryText: '⚠️ Keine offenen Materialien gefunden.', allNeedIds: [], emailCount: 0 } }];
}

const projectId = $('Parse Query Params').first().json.project_id;
const pn = rows[0].project_number;
const projectName = rows[0].project_name;
const address = rows[0].address || '';

// Group by supplier
const bySupplier = {};
const noSupplier = [];

for (const r of rows) {
  if (!r.supplier_id) {
    noSupplier.push(r);
    continue;
  }
  const key = r.supplier_id;
  if (!bySupplier[key]) {
    bySupplier[key] = {
      supplier_id: r.supplier_id,
      supplier_name: r.supplier_name,
      supplier_short: r.supplier_short,
      supplier_email: r.supplier_email,
      supplier_phone: r.supplier_phone,
      items: [],
      need_ids: [],
      total: 0
    };
  }
  const lineValue = (Number(r.total_quantity) || 0) * (Number(r.unit_price_net) || 0);
  bySupplier[key].items.push({
    label: r.label,
    product_name: r.full_product_name || r.product_name || r.label,
    sku: r.sku || '',
    quantity: Number(r.total_quantity),
    unit: r.quantity_unit,
    unit_price: Number(r.unit_price_net) || 0,
    total: lineValue,
    notes: r.notes
  });
  bySupplier[key].need_ids.push(r.need_id);
  bySupplier[key].total += lineValue;
}

const orders = Object.values(bySupplier).filter(o => o.supplier_email);
const noEmail = Object.values(bySupplier).filter(o => !o.supplier_email);

// Build email HTML per supplier
for (const order of orders) {
  let html = `<p>Guten Tag,</p>`;
  html += `<p>wir möchten folgende Materialien bestellen für unser Projekt <b>${pn} – ${projectName}</b>`;
  if (address) html += ` (${address})`;
  html += `:</p>`;
  html += `<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-family:Arial,sans-serif;">`;
  html += `<tr style="background:#f0f0f0"><th>Pos</th><th>Artikel</th><th>Art.Nr.</th><th>Menge</th><th>Einheit</th></tr>`;

  order.items.forEach((item, i) => {
    html += `<tr><td>${i+1}</td><td>${item.product_name}</td><td>${item.sku}</td><td>${item.quantity}</td><td>${item.unit}</td></tr>`;
  });

  html += `</table>`;
  html += `<p>Bitte um Auftragsbestätigung und Liefertermin.</p>`;
  html += `<p>Mit freundlichen Grüßen<br/>Dennis Blöte<br/>Blöte Gebäudemanagement</p>`;

  order.emailHtml = html;
  order.emailSubject = `Bestellung ${pn} – ${order.supplier_short || order.supplier_name}`;
}

// Build summary for Telegram
let summaryLines = [];
summaryLines.push(`✅ <b>Bestellungen versendet für ${pn}</b>`);
summaryLines.push('');

for (const order of orders) {
  summaryLines.push(`📧 <b>${order.supplier_short || order.supplier_name}</b> → ${order.supplier_email}`);
  summaryLines.push(`   ${order.items.length} Pos. · ~€${order.total.toFixed(0)}`);
}

if (noEmail.length > 0) {
  summaryLines.push('');
  summaryLines.push(`⚠️ <b>${noEmail.length} Lieferanten ohne E-Mail</b> (manuell bestellen):`);
  for (const ne of noEmail) {
    summaryLines.push(`  • ${ne.supplier_short || ne.supplier_name}: ${ne.items.length} Pos.`);
  }
}

if (noSupplier.length > 0) {
  summaryLines.push('');
  summaryLines.push(`⚠️ <b>${noSupplier.length} Materialien ohne Lieferant</b>`);
}

const allNeedIds = [...orders, ...noEmail].flatMap(o => o.need_ids);

return [{
  json: {
    orders,
    noEmail,
    noSupplier,
    projectId,
    summaryText: summaryLines.join('\n'),
    allNeedIds,
    emailCount: orders.length
  }
}];

const data = $input.first().json;
const orders = data.orders || [];
if (orders.length === 0) {
  return [{ json: { skipped: true, reason: 'no_email_orders' } }];
}
return orders.map(o => ({ json: o }));

const order = $input.first().json;
if (order.skipped) {
  return [{ json: { sent: false, reason: 'no_email_orders' } }];
}
// In production: would send email to order.supplier_email
// For now: log and continue
return [{ json: { 
  sent: true, 
  supplier: order.supplier_name, 
  email: order.supplier_email, 
  subject: order.emailSubject,
  itemCount: (order.items || []).length
} }];

